{$H+}
program lipdecide;

uses Math;

const
  PI = 3.1415926535;

type
  POINTRANGE  = 1..100;
  LICRANGE    = 1..15;
  NPOINTS     = 2..100;
  NPTYPE      = 3..100;
  CONNECTORS  = (NOTUSED, ORR, ANDD);
  NUMQUADS    = 1..3;
  COORDINATE  = array[POINTRANGE] of real;
  CMATRIX     = array[LICRANGE, LICRANGE] of CONNECTORS;
  BMATRIX     = array[LICRANGE, LICRANGE] of boolean;
  VECTOR      = array[LICRANGE] of boolean;
  COMPTYPE    = (LT, EQ, GT);

var
  X          : COORDINATE;
  Y          : COORDINATE;
  NUMPOINTS  : integer;
  PARAMETERS : record
    LENGTH1  : real;
    RADIUS1  : real;
    EPSILON  : real;
    AREA1    : real;
    Q_PTS    : integer;
    QUADS    : integer;
    DIST     : real;
    N_PTS    : integer;
    K_PTS    : integer;
    A_PTS    : integer;
    B_PTS    : integer;
    C_PTS    : integer;
    D_PTS    : integer;
    E_PTS    : integer;
    F_PTS    : integer;
    G_PTS    : integer;
    LENGTH2  : real;
    RADIUS2  : real;
    AREA2    : real;
  end;
  LCM     : CMATRIX;
  PUM     : BMATRIX;
  CMV     : VECTOR;
  FUV     : VECTOR;
  LAUNCH  : boolean;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

function Dist(x1, y1, x2, y2: real): real;
begin
  Dist := Sqrt(Sqr(x1 - x2) + Sqr(y1 - y2));
end;

function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := 0.5 * Abs(x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2));
end;

function SECRadius(x1, y1, x2, y2, x3, y3: real): real;
var
  a, b, c, area: real;
  a2, b2, c2: real;
begin
  a := Dist(x2, y2, x3, y3);
  b := Dist(x1, y1, x3, y3);
  c := Dist(x1, y1, x2, y2);

  a2 := a * a;
  b2 := b * b;
  c2 := c * c;

  if (REALCOMPARE(a2, b2 + c2) <> LT) then
    SECRadius := a / 2.0
  else if (REALCOMPARE(b2, a2 + c2) <> LT) then
    SECRadius := b / 2.0
  else if (REALCOMPARE(c2, a2 + b2) <> LT) then
    SECRadius := c / 2.0
  else
  begin
    area := TriangleArea(x1, y1, x2, y2, x3, y3);
    if REALCOMPARE(area, 0.0) = EQ then
    begin
      if (REALCOMPARE(a, b) <> LT) and (REALCOMPARE(a, c) <> LT) then SECRadius := a / 2.0
      else if (REALCOMPARE(b, a) <> LT) and (REALCOMPARE(b, c) <> LT) then SECRadius := b / 2.0
      else SECRadius := c / 2.0;
    end
    else
      SECRadius := (a * b * c) / (4.0 * area);
  end;
end;

function GetQuadrant(x, y: real): integer;
begin
  if (REALCOMPARE(x, 0.0) <> LT) and (REALCOMPARE(y, 0.0) <> LT) then GetQuadrant := 1
  else if (REALCOMPARE(x, 0.0) = LT) and (REALCOMPARE(y, 0.0) <> LT) then GetQuadrant := 2
  else if (REALCOMPARE(x, 0.0) <> GT) and (REALCOMPARE(y, 0.0) = LT) then GetQuadrant := 3
  else GetQuadrant := 4;
end;

procedure DECIDE;
var
  i, j, k, p1, p2, p3: integer;
  d, area, angle, cosTheta: real;
  v1x, v1y, v2x, v2y: real;
  quads_count: integer;
  q_used: array[1..4] of boolean;
  dist_to_line: real;
  found1, found2: boolean;
begin
  for i := 1 to 15 do CMV[i] := false;

  { LIC 1 }
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(Dist(X[i], Y[i], X[i+1], Y[i+1]), PARAMETERS.LENGTH1) = GT then
      CMV[1] := true;

  { LIC 2 }
  for i := 1 to NUMPOINTS - 2 do
    if REALCOMPARE(SECRadius(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]), PARAMETERS.RADIUS1) = GT then
      CMV[2] := true;

  { LIC 3 }
  for i := 1 to NUMPOINTS - 2 do
  begin
    p1 := i; p2 := i + 1; p3 := i + 2;
    if ((REALCOMPARE(X[p1], X[p2]) <> EQ) or (REALCOMPARE(Y[p1], Y[p2]) <> EQ)) and
       ((REALCOMPARE(X[p3], X[p2]) <> EQ) or (REALCOMPARE(Y[p3], Y[p2]) <> EQ)) then
    begin
      v1x := X[p1] - X[p2]; v1y := Y[p1] - Y[p2];
      v2x := X[p3] - X[p2]; v2y := Y[p3] - Y[p2];
      angle := ArcTan2(v1x * v2y - v1y * v2x, v1x * v2x + v1y * v2y);
      angle := Abs(angle);
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
        CMV[3] := true;
    end;
  end;

  { LIC 4 }
  for i := 1 to NUMPOINTS - 2 do
    if REALCOMPARE(TriangleArea(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]), PARAMETERS.AREA1) = GT then
      CMV[4] := true;

  { LIC 5 }
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for k := 1 to 4 do q_used[k] := false;
    for j := 0 to PARAMETERS.Q_PTS - 1 do
      q_used[GetQuadrant(X[i+j], Y[i+j])] := true;
    quads_count := 0;
    for k := 1 to 4 do if q_used[k] then quads_count := quads_count + 1;
    if quads_count > PARAMETERS.QUADS then
      CMV[5] := true;
  end;

  { LIC 6 }
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(X[i+1], X[i]) = LT then
      CMV[6] := true;

  { LIC 7 }
  if NUMPOINTS >= 3 then
    for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      p1 := i; p2 := i + PARAMETERS.N_PTS - 1;
      if (REALCOMPARE(X[p1], X[p2]) = EQ) and (REALCOMPARE(Y[p1], Y[p2]) = EQ) then
      begin
        for j := p1 + 1 to p2 - 1 do
          if REALCOMPARE(Dist(X[j], Y[j], X[p1], Y[p1]), PARAMETERS.DIST) = GT then
            CMV[7] := true;
      end
      else
      begin
        for j := p1 + 1 to p2 - 1 do
        begin
          dist_to_line := Abs((Y[p1] - Y[p2]) * X[j] + (X[p2] - X[p1]) * Y[j] + (X[p1] * Y[p2] - X[p2] * Y[p1])) / Dist(X[p1], Y[p1], X[p2], Y[p2]);
          if REALCOMPARE(dist_to_line, PARAMETERS.DIST) = GT then
            CMV[7] := true;
        end;
      end;
    end;

  { LIC 8 }
  if NUMPOINTS >= 3 then
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
      if REALCOMPARE(Dist(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]), PARAMETERS.LENGTH1) = GT then
        CMV[8] := true;

  { LIC 9 }
  if NUMPOINTS >= 5 then
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
      if REALCOMPARE(SECRadius(X[i], Y[i], X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1], X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2], Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2]), PARAMETERS.RADIUS1) = GT then
        CMV[9] := true;

  { LIC 10 }
  if NUMPOINTS >= 5 then
    for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
    begin
      p1 := i; p2 := i + PARAMETERS.C_PTS + 1; p3 := i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2;
      if ((REALCOMPARE(X[p1], X[p2]) <> EQ) or (REALCOMPARE(Y[p1], Y[p2]) <> EQ)) and
         ((REALCOMPARE(X[p3], X[p2]) <> EQ) or (REALCOMPARE(Y[p3], Y[p2]) <> EQ)) then
      begin
        v1x := X[p1] - X[p2]; v1y := Y[p1] - Y[p2];
        v2x := X[p3] - X[p2]; v2y := Y[p3] - Y[p2];
        angle := ArcTan2(v1x * v2y - v1y * v2x, v1x * v2x + v1y * v2y);
        angle := Abs(angle);
        if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
          CMV[10] := true;
      end;
    end;

  { LIC 11 }
  if NUMPOINTS >= 5 then
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
      if REALCOMPARE(TriangleArea(X[i], Y[i], X[i + PARAMETERS.E_PTS + 1], Y[i + PARAMETERS.E_PTS + 1], X[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2], Y[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2]), PARAMETERS.AREA1) = GT then
        CMV[11] := true;

  { LIC 12 }
  if NUMPOINTS >= 3 then
    for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
      if REALCOMPARE(X[i + PARAMETERS.G_PTS + 1], X[i]) = LT then
        CMV[12] := true;

  { LIC 13 }
  if NUMPOINTS >= 3 then
  begin
    found1 := false; found2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      d := Dist(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
      if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then found1 := true;
      if REALCOMPARE(d, PARAMETERS.LENGTH2) = LT then found2 := true;
    end;
    if found1 and found2 then CMV[13] := true;
  end;

  { LIC 14 }
  if NUMPOINTS >= 5 then
  begin
    found1 := false; found2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      d := SECRadius(X[i], Y[i], X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1], X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2], Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2]);
      if REALCOMPARE(d, PARAMETERS.RADIUS1) = GT then found1 := true;
      if REALCOMPARE(d, PARAMETERS.RADIUS2) <> GT then found2 := true;
    end;
    if found1 and found2 then CMV[14] := true;
  end;

  { LIC 15 }
  if NUMPOINTS >= 5 then
  begin
    found1 := false; found2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      area := TriangleArea(X[i], Y[i], X[i + PARAMETERS.E_PTS + 1], Y[i + PARAMETERS.E_PTS + 1], X[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2], Y[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2]);
      if REALCOMPARE(area, PARAMETERS.AREA1) = GT then found1 := true;
      if REALCOMPARE(area, PARAMETERS.AREA2) = LT then found2 := true;
    end;
    if found1 and found2 then CMV[15] := true;
  end;

  for i := 1 to 15 do
    for j := 1 to 15 do
      if i <> j then
      begin
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ANDD:    PUM[i, j] := CMV[i] and CMV[j];
          ORR:     PUM[i, j] := CMV[i] or CMV[j];
        end;
      end;

  for i := 1 to 15 do
  begin
    if not PUM[i, i] then FUV[i] := true
    else
    begin
      FUV[i] := true;
      for j := 1 to 15 do
        if (i <> j) and (not PUM[i, j]) then
        begin
          FUV[i] := false;
          Break;
        end;
    end;
  end;

  LAUNCH := true;
  for i := 1 to 15 do
    if not FUV[i] then
    begin
      LAUNCH := false;
      Break;
    end;
end;

type
  TTokenType = (ttBraceOpen, ttBraceClose, ttBracketOpen, ttBracketClose, ttComma, ttColon, ttString, ttNumber, ttBoolean, ttNull, ttEOF);
  TToken = record
    Typ: TTokenType;
    Str: string;
    Val: real;
    Bool: boolean;
  end;

var
  InputStr: string;
  InputPos: integer;
  CurrentToken: TToken;

procedure NextToken;
var
  s: string;
  code: integer;
begin
  while (InputPos <= Length(InputStr)) and (InputStr[InputPos] in [' ', #9, #10, #13]) do
    Inc(InputPos);

  if InputPos > Length(InputStr) then
  begin
    CurrentToken.Typ := ttEOF;
    Exit;
  end;

  case InputStr[InputPos] of
    '{': begin CurrentToken.Typ := ttBraceOpen; Inc(InputPos); end;
    '}': begin CurrentToken.Typ := ttBraceClose; Inc(InputPos); end;
    '[': begin CurrentToken.Typ := ttBracketOpen; Inc(InputPos); end;
    ']': begin CurrentToken.Typ := ttBracketClose; Inc(InputPos); end;
    ',': begin CurrentToken.Typ := ttComma; Inc(InputPos); end;
    ':': begin CurrentToken.Typ := ttColon; Inc(InputPos); end;
    '"': begin
      s := ''; Inc(InputPos);
      while (InputPos <= Length(InputStr)) and (InputStr[InputPos] <> '"') do
      begin
        s := s + InputStr[InputPos]; Inc(InputPos);
      end;
      Inc(InputPos);
      CurrentToken.Typ := ttString; CurrentToken.Str := s;
    end;
    else
      if InputStr[InputPos] in ['0'..'9', '-', '.'] then
      begin
        s := '';
        while (InputPos <= Length(InputStr)) and (InputStr[InputPos] in ['0'..'9', '-', '.', 'e', 'E', '+']) do
        begin
          s := s + InputStr[InputPos]; Inc(InputPos);
        end;
        Val(s, CurrentToken.Val, code); CurrentToken.Typ := ttNumber;
      end
      else
      begin
        s := '';
        while (InputPos <= Length(InputStr)) and (InputStr[InputPos] in ['a'..'z', 'A'..'Z']) do
        begin
          s := s + InputStr[InputPos]; Inc(InputPos);
        end;
        if s = 'true' then begin CurrentToken.Typ := ttBoolean; CurrentToken.Bool := true; end
        else if s = 'false' then begin CurrentToken.Typ := ttBoolean; CurrentToken.Bool := false; end
        else if s = 'null' then CurrentToken.Typ := ttNull;
      end;
  end;
end;

procedure Expect(t: TTokenType);
begin
  if CurrentToken.Typ = t then NextToken;
end;

function ParseNumber: real;
begin
  ParseNumber := CurrentToken.Val; Expect(ttNumber);
end;

function ParseBoolean: boolean;
begin
  ParseBoolean := CurrentToken.Bool; Expect(ttBoolean);
end;

function ParseString: string;
begin
  ParseString := CurrentToken.Str; Expect(ttString);
end;

procedure ParseInput;
var
  key: string;
  i, j: integer;
begin
  NextToken; Expect(ttBraceOpen);
  while CurrentToken.Typ <> ttBraceClose do
  begin
    key := ParseString; Expect(ttColon);
    if key = 'numpoints' then NUMPOINTS := Round(ParseNumber)
    else if key = 'x' then
    begin
      Expect(ttBracketOpen); i := 1;
      while CurrentToken.Typ <> ttBracketClose do
      begin
        X[i] := ParseNumber; Inc(i);
        if CurrentToken.Typ = ttComma then NextToken;
      end;
      Expect(ttBracketClose);
    end
    else if key = 'y' then
    begin
      Expect(ttBracketOpen); i := 1;
      while CurrentToken.Typ <> ttBracketClose do
      begin
        Y[i] := ParseNumber; Inc(i);
        if CurrentToken.Typ = ttComma then NextToken;
      end;
      Expect(ttBracketClose);
    end
    else if key = 'parameters' then
    begin
      Expect(ttBraceOpen);
      while CurrentToken.Typ <> ttBraceClose do
      begin
        key := ParseString; Expect(ttColon);
        if key = 'LENGTH1' then PARAMETERS.LENGTH1 := ParseNumber
        else if key = 'RADIUS1' then PARAMETERS.RADIUS1 := ParseNumber
        else if key = 'EPSILON' then PARAMETERS.EPSILON := ParseNumber
        else if key = 'AREA1' then PARAMETERS.AREA1 := ParseNumber
        else if key = 'Q_PTS' then PARAMETERS.Q_PTS := Round(ParseNumber)
        else if key = 'QUADS' then PARAMETERS.QUADS := Round(ParseNumber)
        else if key = 'DIST' then PARAMETERS.DIST := ParseNumber
        else if key = 'N_PTS' then PARAMETERS.N_PTS := Round(ParseNumber)
        else if key = 'K_PTS' then PARAMETERS.K_PTS := Round(ParseNumber)
        else if key = 'A_PTS' then PARAMETERS.A_PTS := Round(ParseNumber)
        else if key = 'B_PTS' then PARAMETERS.B_PTS := Round(ParseNumber)
        else if key = 'C_PTS' then PARAMETERS.C_PTS := Round(ParseNumber)
        else if key = 'D_PTS' then PARAMETERS.D_PTS := Round(ParseNumber)
        else if key = 'E_PTS' then PARAMETERS.E_PTS := Round(ParseNumber)
        else if key = 'F_PTS' then PARAMETERS.F_PTS := Round(ParseNumber)
        else if key = 'G_PTS' then PARAMETERS.G_PTS := Round(ParseNumber)
        else if key = 'LENGTH2' then PARAMETERS.LENGTH2 := ParseNumber
        else if key = 'RADIUS2' then PARAMETERS.RADIUS2 := ParseNumber
        else if key = 'AREA2' then PARAMETERS.AREA2 := ParseNumber;
        if CurrentToken.Typ = ttComma then NextToken;
      end;
      Expect(ttBraceClose);
    end
    else if key = 'lcm' then
    begin
      Expect(ttBracketOpen);
      for i := 1 to 15 do
      begin
        Expect(ttBracketOpen);
        for j := 1 to 15 do
        begin
          key := ParseString;
          if key = 'NOTUSED' then LCM[i, j] := NOTUSED
          else if key = 'ORR' then LCM[i, j] := ORR
          else if key = 'ANDD' then LCM[i, j] := ANDD;
          if CurrentToken.Typ = ttComma then NextToken;
        end;
        Expect(ttBracketClose);
        if CurrentToken.Typ = ttComma then NextToken;
      end;
      Expect(ttBracketClose);
    end
    else if key = 'pum_diag' then
    begin
      Expect(ttBracketOpen);
      for i := 1 to 15 do
      begin
        PUM[i, i] := ParseBoolean;
        if CurrentToken.Typ = ttComma then NextToken;
      end;
      Expect(ttBracketClose);
    end;
    if CurrentToken.Typ = ttComma then NextToken;
  end;
  Expect(ttBraceClose);
end;

procedure WriteJSON;
var
  i, j: integer;
begin
  Write('{');
  Write('"cmv":[');
  for i := 1 to 15 do
  begin
    if CMV[i] then Write('true') else Write('false');
    if i < 15 then Write(',');
  end;
  Write('],');
  Write('"pum":[');
  for i := 1 to 15 do
  begin
    Write('[');
    for j := 1 to 15 do
    begin
      if PUM[i, j] then Write('true') else Write('false');
      if j < 15 then Write(',');
    end;
    Write(']');
    if i < 15 then Write(',');
  end;
  Write('],');
  Write('"fuv":[');
  for i := 1 to 15 do
  begin
    if FUV[i] then Write('true') else Write('false');
    if i < 15 then Write(',');
  end;
  Write('],');
  Write('"launch":');
  if LAUNCH then Write('true') else Write('false');
  WriteLn('}');
end;

var
  Line: string;
begin
  InputStr := '';
  while not EOF do
  begin
    ReadLn(Line); InputStr := InputStr + Line;
  end;
  InputPos := 1; ParseInput;
  DECIDE; WriteJSON;
end.
